# Webhook configuration in the Pact Broker
# POST this JSON to your broker's /webhooks endpoint.
# It fires the provider CI whenever any consumer publishes a new pact.
{
  "events": [
    { "name": "contract_content_changed" },
    { "name": "contract_published" }
  ],
  "request": {
    "method": "POST",
    "url": "https://api.github.com/repos/your-org/tool-server/dispatches",
    "headers": {
      "Content-Type": "application/json",
      "Authorization": "Bearer ${user.token}"
    },
    "body": {
      "event_type": "pact-changed",
      "client_payload": {
        "pact_url": "${pactbroker.pactUrl}",
        "consumer_name": "${pactbroker.consumerName}",
        "consumer_version": "${pactbroker.consumerVersionNumber}",
        "provider_name": "${pactbroker.providerName}"
      }
    }
  }
}
